# RANDOM FOREST #REGRESSION#CLASSIFICATON##ENSEMBLE LEARNING#.PARALLEL BAGING#.SEQENTION BOOSTING### PARALLEL LEARNING#RT we are calculate avg is called bootstrap aggregator#Classification import numpy as npimport matplotlib.pyplot as pltimport pandas as pd# Load datasetdataset = pd.read_csv(r"/Users/afsarazam/Desktop/ML tools& tech/salary_data.csv")# Features (X) and Target (y)x = dataset.iloc[:, :-1].valuesy = dataset.iloc[:, -1].values  # Train-Test Splitfrom sklearn.model_selection import train_test_splitx_train, x_test, y_train, y_test = train_test_split(x, y, test_size=0.15, random_state=0)from sklearn.ensemble import RandomForestRegressormodel = RandomForestRegressor(n_estimators=100, random_state=0)# Train modelmodel.fit(x_train, y_train)# Predictionsy_pred = model.predict(x_test)# Evaluationfrom sklearn.metrics import r2_scoreprint("R2 Score:", r2_score(y_test, y_pred))